let score = 10;
score = 25;          // مسموح: إعادة إسناد let
console.log(score);

const siteName = "منصتنا";
console.log(siteName);
// siteName = "غيره"; // خطأ! لا يمكن تغيير const

if (true) {
  var oldWay = "أنا var أتسرب خارج الكتلة";
  let newWay = "أنا let محبوسة داخل الكتلة";
}
console.log(oldWay);      // يعمل — تسرب!
try { console.log(newWay); } catch (e) { console.log("newWay غير معرفة هنا ✓"); }

